看到锤子广告，点错进了锤子官网，首页有个特效炒鸡有意思啊！可是能力不够，百思不得其解……开始以为是纯JQUERY，到网上搜了下发现用CSS就可以实现了，是利用CSS的3个图层的景深不一致，旋转得到的。(。・ &#96;ω´ ・) 
先贴 DEMO



代码DOM部分&lt;div class=&quot;banner&quot;&gt;    &lt;div class=&quot;bg&quot;&gt;        &lt;span class=&quot;img a&quot;&gt;&lt;/span&gt;        &lt;span class=&quot;text b&quot;&gt;以傲慢与偏执&lt;br/&gt;回敬傲慢与偏见&lt;/span&gt;        &lt;span class=&quot;copyright c&quot;&gt;code by qingjin.me | picture from t.tt&lt;/span&gt;      &lt;/div&gt;&lt;/div&gt;

CSS部分* &#123;    font-family: &quot;Microsoft YaHei&quot;;    transition: all .3s;    -webkit-transition: all .3s;    transition-timing-function: linear;    -webkit-transition-timing-function: linear;&#125;.banner &#123; /* 产生景深*/    perspective: 800px;&#125;/*背景图*/.bg &#123;/* 启用父元素定位 距离父元素上部100px 居中*/    position: relative;    width: 600px;    height: 300px;    margin: 100px auto;    background: url(&quot;http://static.smartisanos.cn/index/img/store/home/banner-3d-item-1-box-1_61bdc2f4f9.png&quot;) center no-repeat;    background-size: 100% 100%;    border-radius: 10px;    /*            转化为3D图形 设置旋转基点为图片中心 默认不旋转*/    transform-style: preserve-3d;    -webkit-transform-origin: 50% 50%;    -webkit-transform: rotateY(0deg) rotateX(0deg);&#125;/* 商品图（突出显示部分）*/.img &#123;    position: absolute;    width: 100%;    height: 100%;    /*            元素向上移动8px 突出手机上部*/    bottom: 8px;    left: 0;    background: url(&quot;http://static.smartisanos.cn/index/img/store/home/banner-3d-item-1-box-3_8fa7866d59.png&quot;) center no-repeat;    background-size: 95% 100%;&#125;/* 文字*/.text &#123;    position: absolute;    top: 20%;    right: 10%;    font-size: 30px;    color: #fff;    text-align: right;    font-weight: lighter;&#125;.copyright &#123;    position: absolute;    bottom: 10%;    right: 10%;    font-size: 10px;    color: #fff;    text-align: right;    font-weight: lighter;&#125;/*    重点  将 前(商品图片)、中( 文字)、后(背景图片-灰色价格) 三层分离 视距20px；*/.a &#123;    -webkit-transform: translateZ(40px);&#125;.b &#123;    -webkit-transform: translateZ(20px);&#125;.c &#123;    -webkit-transform: translateZ(0px);&#125;


Js$(function () &#123;       //鼠标进入后  计算鼠标在banner中的位置 除系数50 旋转banner       $(&quot;.bg&quot;).mouseenter(function () &#123;                          var thisPX = $(this).offset().left;           var thisPY = $(this).offset().top;           var boxWidth = $(this).outerWidth();           var boxHeight = $(this).outerHeight();           $(this).addClass(&quot;threeD&quot;);           $(&quot;.threeD&quot;).mousemove(function (event) &#123;               var mouseX = event.pageX - thisPX;               var mouseY = event.pageY - thisPY;               var X;               var Y;               if (mouseX &gt; boxWidth / 2) &#123;                   X = mouseX - boxWidth / 2;               &#125; else &#123;                   X = mouseX - boxWidth / 2;               &#125;               if (mouseY &gt; boxHeight / 2) &#123;                   Y = boxHeight / 2 - mouseY;               &#125; else &#123;                   Y = boxHeight / 2 - mouseY;               &#125;               $(&quot;.threeD&quot;).css(&#123;                   &quot;-webkit-transform&quot;: &quot;rotateY(&quot; + X / 50 + &quot;deg) &quot; + &quot;rotateX(&quot;  + Y / 50 + &quot;deg)&quot;               &#125;);               // console.log(X + &quot;,&quot; + Y);           &#125;);       &#125;);       $(&quot;.bg&quot;).mouseleave(function () &#123;           $(this).removeClass(&quot;threeD&quot;);           $(this).css(&#123;               &quot;-webkit-transform&quot;: &quot;rotateY(0deg) rotateX(0deg)&quot;           &#125;);       &#125;);   &#125;);


原帖：锤子官网 banner 图 3D 效果实现方法

